def _safe_path(rel_path: str) -> str:
    base = os.path.abspath(config.WORKSPACE_DIR)
    full = os.path.abspath(os.path.join(base, rel_path))
    # Fix: cek exact match ATAU base + separator, bukan cuma prefix string.
    # Prefix string doang bisa ketipu folder sibling, misal base="/x/workspace"
    # dan full="/x/workspace_backup/rahasia.txt" -> startswith() true padahal
    # itu di luar workspace.
    if not (full == base or full.startswith(base + os.sep)):
        raise ValueError("Path di luar workspace, ditolak demi keamanan.")
    return full


def fetch_url(url: str) -> str:
    try:
        import requests
        from bs4 import BeautifulSoup

        resp = requests.get(url, timeout=15, headers={"User-Agent": "Mozilla/5.0 (SOVEREIGN Agent)"})
        resp.raise_for_status()
        soup = BeautifulSoup(resp.text, "html.parser")
        for tag in soup(["script", "style", "nav", "footer", "header"]):
            tag.decompose()
        text = " ".join(soup.get_text(separator=" ", strip=True).split())
        return text[:6000]
    except ImportError:
