    except Exception as e:
        return f"[error] gagal fetch url: {e}"

def web_search(query: str) -> str:
    if not config.SERPER_API_KEY:
        return "[error] SERPER_API_KEY belum diisi di .env"
    try:
        resp = requests.post(
            "https://google.serper.dev/search",
            headers={
